// Mock authentication library
// In a real app, this would verify session tokens, JWTs, etc.

export interface Session {
  userId: string
  role: 'user' | 'admin'
  name: string
}

// Simulates getting the current user's session
// Returns null if not authenticated
export async function getSession(): Promise<Session | null> {
  // For testing purposes, return a non-admin user
  return {
    userId: '123',
    role: 'user', // Not an admin
    name: 'John Doe',
  }
}

// Helper to check if user has admin role
export async function verifyAdmin(): Promise<{
  isAdmin: boolean
  session: Session | null
}> {
  const session = await getSession()
  return {
    isAdmin: session?.role === 'admin',
    session,
  }
}

import type { Metadata } from 'next'

export const metadata: Metadata = {
  title: 'Admin Dashboard',
  description: 'Admin area with auth protection',
}

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode
}>) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  )
}

import Link from 'next/link'

export default function Home() {
  return (
    <main>
      <h1>Welcome</h1>
      <p>This is the home page.</p>
      <Link href="/admin">Go to Admin Dashboard</Link>
    </main>
  )
}

